import{_ as s,o as n,c as t,a3 as e}from"./chunks/framework.DACwFHq9.js";const k=JSON.parse('{"title":"Kafka 副本机制","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"middleware/kafka/replication.md","filePath":"middleware/kafka/replication.md","lastUpdated":1780474278000}'),i={name:"middleware/kafka/replication.md"};function l(p,a,r,d,o,h){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="kafka-fu-ben-ji-zhi" tabindex="-1">Kafka 副本机制 <a class="header-anchor" href="#kafka-fu-ben-ji-zhi" aria-label="Permalink to &quot;Kafka 副本机制&quot;">​</a></h1><h2 id="fu-ben-jia-gou" tabindex="-1">副本架构 <a class="header-anchor" href="#fu-ben-jia-gou" aria-label="Permalink to &quot;副本架构&quot;">​</a></h2><p>Kafka 为每个 Partition 维护多份副本，分布在不同的 Broker 上，实现<strong>高可用</strong>和<strong>数据不丢失</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>     Topic &quot;orders&quot;, Partition 0, Replication Factor = 3</span></span>
<span class="line"><span>                ┌─────────────────────────┐</span></span>
<span class="line"><span>                │       Broker 1           │</span></span>
<span class="line"><span>                │   ┌─────────────────┐   │</span></span>
<span class="line"><span>                │   │  Leader (P0)    │   │  ← 所有读写</span></span>
<span class="line"><span>                │   │  Offset 0..999  │   │</span></span>
<span class="line"><span>                │   └─────────────────┘   │</span></span>
<span class="line"><span>                └──────────┬──────────────┘</span></span>
<span class="line"><span>                           │ 数据同步</span></span>
<span class="line"><span>                ┌──────────▼──────────────┐</span></span>
<span class="line"><span>                │       Broker 2           │</span></span>
<span class="line"><span>                │   ┌─────────────────┐   │</span></span>
<span class="line"><span>                │   │  Follower (P0)  │   │</span></span>
<span class="line"><span>                │   │  Offset 0..998  │   │  ← ISR</span></span>
<span class="line"><span>                │   └─────────────────┘   │</span></span>
<span class="line"><span>                └──────────┬──────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>                ┌──────────▼──────────────┐</span></span>
<span class="line"><span>                │       Broker 3           │</span></span>
<span class="line"><span>                │   ┌─────────────────┐   │</span></span>
<span class="line"><span>                │   │  Follower (P0)  │   │</span></span>
<span class="line"><span>                │   │  Offset 0..950  │   │  ← lag=49, 不在 ISR</span></span>
<span class="line"><span>                │   └─────────────────┘   │</span></span>
<span class="line"><span>                └─────────────────────────┘</span></span></code></pre></div><h2 id="guan-jian-gai-nian" tabindex="-1">关键概念 <a class="header-anchor" href="#guan-jian-gai-nian" aria-label="Permalink to &quot;关键概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td><strong>Leader</strong></td><td>负责该 Partition 的<strong>所有读写</strong>，每个 Partition 只有一个 Leader</td></tr><tr><td><strong>Follower</strong></td><td>被动从 Leader 拉取并同步数据，不处理客户端请求</td></tr><tr><td><strong>ISR</strong> (In-Sync Replicas)</td><td>与 Leader 保持同步的副本集合，能及时追上 Leader 的写入</td></tr><tr><td><strong>OSR</strong> (Out-of-Sync Replicas)</td><td>已落后于 Leader（<code>replica.lag.time.max.ms</code> 阈值）的副本</td></tr><tr><td><strong>HW</strong> (High Watermark)</td><td>ISR 中所有副本都已写入的最小 Offset，Consumer 最多读到 HW</td></tr><tr><td><strong>LEO</strong> (Log End Offset)</td><td>副本已写入的最新 Offset（含未提交）</td></tr></tbody></table><h3 id="isr-pan-ding" tabindex="-1">ISR 判定 <a class="header-anchor" href="#isr-pan-ding" aria-label="Permalink to &quot;ISR 判定&quot;">​</a></h3><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看 ISR 状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-topics.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --topic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> orders</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Partition: 0  Leader: 1  Replicas: 1,2,3  Isr: 1,2  (3 掉出 ISR)</span></span></code></pre></div><p>Follower 掉出 ISR 的条件：<code>副本 LEO 落后 Leader LEO 的时间 &gt; replica.lag.time.max.ms</code>（默认 30s）。</p><blockquote><p>v2.5 前还有一个基于消息数的 lag 判断（<code>replica.lag.max.messages</code>），现已移除。</p></blockquote><h2 id="leader-xuan-ju" tabindex="-1">Leader 选举 <a class="header-anchor" href="#leader-xuan-ju" aria-label="Permalink to &quot;Leader 选举&quot;">​</a></h2><p>当 Leader 故障时，Kafka Controller 从 <strong>ISR 列表中选择新的 Leader</strong>。</p><h3 id="xuan-ju-liu-cheng" tabindex="-1">选举流程 <a class="header-anchor" href="#xuan-ju-liu-cheng" aria-label="Permalink to &quot;选举流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Broker 1 (Leader) × 故障</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>Controller (Broker 2) 检测到 Broker 1 不可用</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 从 Partition 0 的 ISR [1, 2, 3] 中排除 1</span></span>
<span class="line"><span>    ├── 选择 ISR 中第一个可用副本 ← Broker 2</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── 广播 LeaderAndIsr 请求，新 Leader = Broker 2</span></span></code></pre></div><h3 id="unclean-leader-election" tabindex="-1">Unclean Leader Election <a class="header-anchor" href="#unclean-leader-election" aria-label="Permalink to &quot;Unclean Leader Election&quot;">​</a></h3><p>当 ISR 为空（所有副本都挂了或掉出 ISR）时，是否允许从 OSR 中选 Leader：</p><table tabindex="0"><thead><tr><th>配置</th><th>行为</th><th>风险</th></tr></thead><tbody><tr><td><code>unclean.leader.election.enable=false</code>（默认）</td><td>等待 ISR 副本恢复</td><td>这段时间 Partition <strong>不可用</strong></td></tr><tr><td><code>unclean.leader.election.enable=true</code></td><td>从 OSR 选 Leader，尽快恢复</td><td><strong>丢数据</strong>（OSR 未同步的消息丢失）</td></tr></tbody></table><blockquote><p>生产环境建议保持 <code>false</code>，优先一致性。</p></blockquote><h2 id="fu-ben-tong-bu-ji-zhi" tabindex="-1">副本同步机制 <a class="header-anchor" href="#fu-ben-tong-bu-ji-zhi" aria-label="Permalink to &quot;副本同步机制&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Producer ──write──► Leader (Broker 1)</span></span>
<span class="line"><span>                      │</span></span>
<span class="line"><span>                      ├── 写入本地日志 (LEO+1)</span></span>
<span class="line"><span>                      │</span></span>
<span class="line"><span>                      ├── Follower (Broker 2) ──fetch──► 拉取数据</span></span>
<span class="line"><span>                      │       ├── 写入本地日志 (LEO+1)</span></span>
<span class="line"><span>                      │       └── 告知 Leader 已同步</span></span>
<span class="line"><span>                      │</span></span>
<span class="line"><span>                      ├── Follower (Broker 3) ──fetch──► 拉取数据</span></span>
<span class="line"><span>                      │       └── 同上</span></span>
<span class="line"><span>                      │</span></span>
<span class="line"><span>                      └── 所有 ISR 确认 (acks=all)</span></span>
<span class="line"><span>                          └── HW 推进 → Consumer 可消费</span></span></code></pre></div><h3 id="he-xin-pei-zhi" tabindex="-1">核心配置 <a class="header-anchor" href="#he-xin-pei-zhi" aria-label="Permalink to &quot;核心配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>参数</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>replication.factor</code></td><td>1</td><td>Topic 级别副本数（Broker 级 <code>default.replication.factor</code>）</td></tr><tr><td><code>min.insync.replicas</code></td><td>1</td><td>Topic/Broker 级最小 ISR 数</td></tr><tr><td><code>replica.lag.time.max.ms</code></td><td>30000（30s）</td><td>Follower 与 Leader 的最大同步延迟</td></tr><tr><td><code>replica.fetch.max.bytes</code></td><td>1MB</td><td>Follower 每个 Fetch 请求的最大字节数</td></tr><tr><td><code>replica.fetch.wait.max.ms</code></td><td>500</td><td>Follower 等待新数据的最大时间</td></tr><tr><td><code>unclean.leader.election.enable</code></td><td><code>false</code></td><td>是否允许 OSR 副本选为 Leader</td></tr><tr><td><code>num.replica.fetchers</code></td><td>1</td><td>Follower 拉取线程数（调大可加速同步）</td></tr></tbody></table><h3 id="mininsyncreplicas-yu-acksall" tabindex="-1">min.insync.replicas 与 acks=all <a class="header-anchor" href="#mininsyncreplicas-yu-acksall" aria-label="Permalink to &quot;min.insync.replicas 与 acks=all&quot;">​</a></h3><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 安全配置：避免 Leader 单点故障导致数据丢失</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// acks=all + min.insync.replicas=2 + replication.factor=3</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">props.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">put</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;acks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;all&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">props.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">put</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;min.insync.replicas&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">props.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">put</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;replication.factor&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;3&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><table tabindex="0"><thead><tr><th>replication.factor</th><th>min.insync.replicas</th><th>容忍故障 Broker 数</th><th>数据安全</th></tr></thead><tbody><tr><td>3</td><td>1</td><td>2</td><td>低（Leader 写入即返回，Follower 可能全挂）</td></tr><tr><td>3</td><td>2</td><td>1</td><td>高（至少 1 个 Follower 确认）</td></tr><tr><td>3</td><td>3</td><td>0</td><td>最高（全确认，但任一 Broker 故障则写入阻塞）</td></tr></tbody></table><h2 id="fu-ben-guan-li" tabindex="-1">副本管理 <a class="header-anchor" href="#fu-ben-guan-li" aria-label="Permalink to &quot;副本管理&quot;">​</a></h2><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看副本分布和 ISR 状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-topics.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --topic</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> orders</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看 Topic 副本分布</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-replica-verification.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --broker-list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看 Under-Replicated Partitions</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kafka-metadata-quorum.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --describe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --status</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bootstrap-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localhost:9092</span></span></code></pre></div><h3 id="controller-jiao-se" tabindex="-1">Controller 角色 <a class="header-anchor" href="#controller-jiao-se" aria-label="Permalink to &quot;Controller 角色&quot;">​</a></h3><p>Controller 是 Kafka 集群中负责管理 Partition 和副本状态的 Broker：</p><table tabindex="0"><thead><tr><th>职责</th><th>说明</th></tr></thead><tbody><tr><td>Leader 选举</td><td>检测 Broker 故障，从 ISR 中选择新 Leader</td></tr><tr><td>ISR 管理</td><td>决定 Follower 进入/退出 ISR</td></tr><tr><td>Partition 分配</td><td>新 Topic / 扩容时分配 Partition 到 Broker</td></tr><tr><td>元数据广播</td><td>将 Leader/ISR 变更广播到所有 Broker</td></tr></tbody></table><p>Controller 选举（KRaft 模式）由 <strong>KRaft Quorum Leader</strong> 担任，ZK 模式下由 ZooKeeper 进行 Broker 间的 Controller 选举。</p><h2 id="can-kao" tabindex="-1">参考 <a class="header-anchor" href="#can-kao" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://kafka.apache.org/documentation/#replication" target="_blank" rel="noreferrer">Kafka Replication</a></li><li><a href="https://kafka.apache.org/documentation/#brokerconfigs" target="_blank" rel="noreferrer">Kafka Broker Configs</a></li><li><a href="https://kafka.apache.org/documentation/#design_replicatedlog" target="_blank" rel="noreferrer">Kafka ISR Design</a></li></ul>`,33)])])}const g=s(i,[["render",l]]);export{k as __pageData,g as default};
